import os

# List the files in the file storage directory
files = []
for root, dirs, filenames in os.walk('file_storage'):
    for filename in filenames:
        filepath = os.path.join(root, filename)
        files.append(filepath)

print('Available files:')
for f in files:
    print(f'  {f}')

# Check if we have the data in memory
available_vars = []
for name, value in locals().items():
    if 'var_functions' in name:
        if isinstance(value, dict):
            available_vars.append(f'{name} (dict with {len(value)} keys)')
        elif isinstance(value, str):
            available_vars.append(f'{name} (string)')

print('\n\nAvailable variables:')
for var in available_vars:
    print(f'  {var}')

